class Solution:
    def letterCasePermutation(self, s: str) -> List[str]:
        ans = []
        def dfs(i, path):
            if i == len(s):
                ans.append("".join(path)); return
            if s[i].isalpha():
                path.append(s[i].lower()); dfs(i+1, path); path.pop()
                path.append(s[i].upper()); dfs(i+1, path); path.pop()
            else:
                path.append(s[i]); dfs(i+1, path); path.pop()
        dfs(0, [])
        return ans

